<template>
  <div>
    <div v-if="isLoading" class="text-center">
      <b-spinner variant="primary" label="Spinning" class="m-5"></b-spinner>
    </div>
    <template v-else>
      <b-form @submit.prevent.stop="onSubmit">
        <h1>Test your self</h1>
        <b-form-group
          v-for="quiz in quizs"
          :key="quiz._id"
          :label="quiz.question"
        >
          <b-form-radio-group
            v-model="quiz.answer"
            :options="quiz.options"
            :state="quiz.isCorrect"
            :disabled="isSubmit"
          >
            <b-form-invalid-feedback :state="quiz.isCorrect">
              Correct answer is: {{ quiz.correctAnswer }}
            </b-form-invalid-feedback>
            <b-form-valid-feedback :state="quiz.isCorrect">
              Good
            </b-form-valid-feedback></b-form-radio-group
          >
        </b-form-group>
        <b-form-group>
          <b-button type="submit" variant="primary" block :disabled="isSubmit">
            Submit
          </b-button>
        </b-form-group>
      </b-form>
    </template>
  </div>
</template>

<script>
import ExamsService from "@/services/ExamsService";

export default {
  data() {
    return {
      isLoading: true,
      quizs: [],
      id: null,
      isSubmit: false,
      createdDate: null,
    };
  },
  mounted() {
    this.getExam(this.$route.params.id);
  },
  methods: {
    shuffle(array) {
      for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
      }
      return array;
    },
    onSubmit() {
      ExamsService.mark(this.id, this.quizs).then((response) => {
        const { data } = response;
        this.quizs.forEach((item) => {
          var quiz = data.quizs.find((i) => i._id === item._id);
          item.isCorrect = quiz.answer === quiz.correct_answer;
          item.correctAnswer = quiz.correct_answer;
        });
        this.id = data._id;
        this.isSubmit = data.is_submit;
      });
    },
    getExam(id) {
      this.isLoading = true;
      ExamsService.get(id).then((response) => {
        const { data } = response;
        this.quizs = data.quizs;
        this.id = data._id;
        this.isSubmit = data.is_submit;
        this.createdDate = data.created_date;
        this.isLoading = false;
      });
    },
  },
};
</script>

